#!/bin/bash
PATTERN=$1
query.sh search-functions "$PATTERN" | python3 -c "import sys, json; print(len(json.load(sys.stdin)))"

vim_plugin_example.hover_function:
function! GeneroHover()
  let word = expand('<cword>')
  let cmd = 'query.sh find-function ' . word
  let result = system(cmd)
  echo result
endfunction

vim_plugin_example.completion_function:
function! GeneroComplete(findstart, base)
  if a:findstart
    return col('.') - 1
  endif
  let cmd = 'query.sh search-functions ' . a:base . '*'
  let results = system(cmd)
  return json_decode(results)
endfunction

vim_plugin_example.goto_definition:
function! GeneroGotoDefinition()
  let word = expand('<cword>')
  let cmd = 'query.sh find-function ' . word
  let result = system(cmd)
  let data = json_decode(result)
  if len(data) > 0
    execute 'edit ' . data[0]['file']
    execute 'goto ' . data[0]['line_start']
  endif
endfunction
